package com.example.lessondesign.controller; import com.example.lessondesign.bean.*; import com.example.lessondesign.dao.*; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/exercises") public class ExerciseController { @Autowired private ExerciseDao exerciseDao; @Autowired private ClassExerciseDao classExerciseDao; @GetMapping public ResponseEntity<List<Exercise>> getAll(){ return ResponseEntity.ok(exerciseDao.findAll()); } @GetMapping("/{id}") public ResponseEntity<Exercise> getById(@PathVariable int id){ Exercise e=exerciseDao.findById(id); return e!=null?ResponseEntity.ok(e):ResponseEntity.notFound().build(); } @PostMapping public ResponseEntity<Exercise> create(@RequestBody Exercise e){ e.setCreatedAt(new Date());e.setUpdatedAt(new Date());e.setStatus("ACTIVE"); exerciseDao.insert(e); return ResponseEntity.ok(e); } @GetMapping("/class/{cid}") public ResponseEntity<List<Exercise>> getByClass(@PathVariable int cid){ return ResponseEntity.ok(exerciseDao.findByClassId(cid)); } @PostMapping("/assign") public ResponseEntity<Map<String,Object>> assign(@RequestBody ClassExercise ce){ Map<String,Object> r=new HashMap<>(); ce.setCreatedAt(new Date()); int ok=classExerciseDao.insert(ce); r.put("success",ok>0);r.put("id",ce.getId()); return ResponseEntity.ok(r); } }